var e=JSON.parse(`[{"id":"L2_1","type":"narration","speaker":null,"text":{"KOREA":"최초의 기억은 텅 빈 방에 홀로 앉아 환청으로 여겨지는 목소리를 듣는 것이었다.","JPN":"最初の記憶は空っぽの部屋に一人で座り、幻聴と思われる声を聞くことだった。","ENG":"My earliest memory was sitting alone in an empty room, listening to a voice that seemed like an auditory hallucination.","TWN":"最初的記憶是獨自坐在空蕩蕩的房間裡，聽到彷彿幻聽般的聲音。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"narration","speaker":null,"text":{"KOREA":"대대로 단명하는 인도자의 소임을 다하기 위해 조속한 시간 내에 별빛을 느껴야만 했고.","JPN":"代々短命であった導き手の役目を果たすため、早いうちに星の光を感じ取らなければならず。","ENG":"To fulfill the duty of the Star Guide, whose line died young for generations, one had to sense starlight as early as possible.","TWN":"為了履行代代早逝的引導者的職責，必須儘快感受到星光。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"narration","speaker":null,"text":{"KOREA":"때문에, 어린 후계자가 모든 것을 짊어지는 상황을 부당하다 말하는 사람은 없었다.","JPN":"幼い後継者がすべてを背負う状況を、誰も不当だとは言わなかった。","ENG":"No one spoke of how unjust it was for a child heir to bear the weight of it all.","TWN":"因此，沒有人會說讓年輕的繼承者承擔一切是不公平的。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"narration","speaker":null,"text":{"KOREA":"모두를 이끄리란 인도자의 전승은 가문에게 있어 그 무엇보다 귀중했으니.","JPN":"皆を導くという導き手の伝承は、家門にとって何よりも重要だったから。","ENG":"The legend of the Guide of leading the people was more precious to the house than anything else.","TWN":"引領眾人的引導者的傳承對家族來說比任何東西都珍貴。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JUDGE_PRIDE_NULL_NULL","text":{"KOREA":"-이상. 제국의 법령에 따라 마왕을 추종한 죄인에게 사형을 고한다.","JPN":"……以上。帝国の法令により、魔王に従った罪人に死刑を告げる。","ENG":"By imperial decree, the traitor who followed the Demon Lord is hereby sentenced to death.","TWN":"-以上。根據帝國法令，對追隨魔王的罪人判處死刑。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LACKEY_RIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"JUDGE_PRIDE_NULL_NULL","text":{"KOREA":"죄인. 집행 전 마지막으로 할 말은 있는가?","JPN":"罪人。執行の前に、最後に残したい言葉はあるか？","ENG":"Prisoner. Any last words before the execution?","TWN":"罪人。執行前有什麼最後的話要說嗎？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LACKEY_RIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LACKEY_RIDE_NULL_NULL","text":{"KOREA":"위대하신 네헤모트가 이 세계에 안녕을 고하기 위해 강림하셨으니.","JPN":"偉大なるネヘモトがこの世界に最後を告げるために降臨された。","ENG":"The great Nehemoth has descended to bid this world farewell.","TWN":"偉大的貝赫莫特降臨此世，向這個世界告別。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LACKEY_RIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LACKEY_RIDE_NULL_NULL","text":{"KOREA":"미천한 네놈들은 나헤마의 불꽃에 휩싸여 재로 돌아갈 것이다…!!","JPN":"下賤な貴様らはナヘマの炎に囲まれ、灰に還るだろう……！！","ENG":"You wretches shall be engulfed by Nahema's flames and turned to ash...!!","TWN":"你們這些卑微的傢伙將會被納赫瑪的火焰吞噬，化為灰燼…！！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LACKEY_RIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JUDGE_PRIDE_NULL_NULL","text":{"KOREA":"……집행하라.","JPN":"……執行しろ。","ENG":"...Carry out the sentence.","TWN":"……執行吧。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LACKEY_RIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LACKEY_RIDE_NULL_NULL","text":{"KOREA":"마왕이시여… 부디…….","JPN":"魔王よ……どうか……","ENG":"O, Demon Lord... please...","TWN":"魔王啊……請你……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LACKEY_RIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LACKEY_RIDE_NULL_NULL","text":{"KOREA":"저에게… 구원을…….","JPN":"私に……救いを……","ENG":"Grant me... salvation...","TWN":"賜我……救贖……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LACKEY_RIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CHIEF_PRIDE_NULL_NULL","text":{"KOREA":"잘 봐두어라. 저것이 궤도에서 벗어난 뒤틀린 별의 최후이니.","JPN":"しっかり見ておくんだ。あれが軌道から外れ、歪んだ星の最期だ。","ENG":"Watch closely. That is the end of a star that strayed from its path.","TWN":"好好看著吧。那就是偏離軌道的扭曲星星的終結。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CHIEF_PRIDE_NULL_NULL","text":{"KOREA":"저들이 앞다투어 절망을 야기하기 전, 인도자의 혈맥인 우리는 신민들을 올바른 길로 이끌어야 한다.","JPN":"あの者たちが先を争い絶望をもたらす前に、導き手の血脈である私たちは臣民を正しい道へと導かねばならない。","ENG":"Before they can drag the world into despair, it falls to us, the bloodline of the Star Guide, to lead our people down the righteous path.","TWN":"在他們爭先恐後地引發絕望之前，作為引導者血脈的我們必須將臣民引導到正確的道路上。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CHIEF_PRIDE_NULL_NULL","text":{"KOREA":"너는 총명하니 이 아비의 말이 무슨 뜻인지 알겠지?","JPN":"お前は聡明だから、この父の話がわかるな？","ENG":"You're clever. You understand what I mean, don't you?","TWN":"你聰明，應該明白為父的話是什麼意思吧？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"GRACE_CHILD_NULL_NULL","text":{"KOREA":"……예. 아버님.","JPN":"……はい、お父様。","ENG":"...Yes, Father.","TWN":"……是的。父親。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CHIEF_PRIDE_NULL_NULL","text":{"KOREA":"지금의 광경을 잊지 말거라, 그레이스.","JPN":"今の光景を忘れるな、グレース。","ENG":"Remember this sight, Grace.","TWN":"不要忘記現在的景象，葛瑞絲。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CHIEF_PRIDE_NULL_NULL","text":{"KOREA":"네가 판단을 그르친다면, 저 피웅덩이의 주인은 무고한 신민들의 것이 될 것이야.","JPN":"お前が間違った判断をすれば、あの血溜まりの主人は罪なき臣民となるだろう。","ENG":"If you ever fail in judgment, it'll be the innocent who end up in that pool of blood.","TWN":"如果你判斷失誤，那麼那個血泊的主人將會是無辜的臣民。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"narration","speaker":null,"text":{"KOREA":"누군가의 뜻에 따라 살아온 인생이지만 불만은 없었다.","JPN":"言われるがままに生きてきた人生だが、不満はなかった。","ENG":"I never resented a life lived according to someone else's will.","TWN":"雖然一直按照別人的意願生活，但我並沒有不滿。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"narration","speaker":null,"text":{"KOREA":"주어진 것에 안주하며 묵묵히 소임을 다하는 것은 내게 어려운 일이 아니었으니까.","JPN":"与えられたものに満足し、黙々と役目を果たすのは私にとって難しいことではなかったから。","ENG":"Fulfilling the role I was given without complaint wasn't difficult for me.","TWN":"安於現狀，默默履行職責對我來說並不困難。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"KNIGH_PRIDE_NULL_A","text":{"KOREA":"인도자님. 요새 통 웃지를 않으시네.","JPN":"導き手、最近まったくお笑いにならないですね。","ENG":"The Star Guide, she hasn't smiled lately.","TWN":"引導者大人，最近都不怎麼笑呢。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGH_PRIDE_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGH_PRIDE_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"KNIGH_PRIDE_NULL_A","text":{"KOREA":"요즘 끼니도 종종 거르시던데, 이러다 탈이라도 나는 건 아닌지 모르겠어.","JPN":"最近は食事を抜くことがあるし、このままだと体調を崩してしまうんじゃないか？","ENG":"She's been skipping meals too. Perhaps she's been pushing herself too hard?","TWN":"最近你經常不按時吃飯，我擔心這樣下去會不會出什麼問題。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGH_PRIDE_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGH_PRIDE_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"KNIGH_PRIDE_NULL_B","text":{"KOREA":"어쩔 수 없지. 최근 연이은 패전으로 왕가에서도 백작가를 독촉하고 있잖아.","JPN":"仕方ない。最近敗戦が続いているから、王家も伯爵家に催促をしてる。","ENG":"She can't help it. After all those losses, the royal family's been pressuring the Count.","TWN":"沒辦法。最近接連的敗戰讓王室也在催促伯爵領地。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGH_PRIDE_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGH_PRIDE_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"KNIGH_PRIDE_NULL_B","text":{"KOREA":"당장 사라진 대륙이 한 둘이 아닌데. 무구의 단조를 기다려달라고 할 수 있겠어?","JPN":"次々と大陸が消えているからな。武具の鍛造を待ってくれとはもう言えないんだろう。","ENG":"With continents vanishing left and right, how could we ask them to wait for the forging of an Armament?","TWN":"現在消失的大陸不止一個。能讓我們等著鍛造武具嗎？"},"stage":{"bg":"SKY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGH_PRIDE_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGH_PRIDE_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"narration","speaker":null,"text":{"KOREA":"후계자로서의 교육이 끝났을 무렵, 나는 호위를 거느리고 제국을 누비기 시작했다.","JPN":"後継者としての教育が終わった頃、私は護衛を連れて帝国を回り始めた。","ENG":"Once my training as an heir was complete, I began traveling the Empire with an escort.","TWN":"作為繼承人的教育結束後，我開始帶著護衛在帝國中巡視。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"narration","speaker":null,"text":{"KOREA":"풍요로운 백작령과는 달리 기근과 죽음이 넘쳐나는 곳이 여정의 태반이었으나.","JPN":"裕福な伯爵領とは違い、飢饉と死が日常化しているところがほとんどであったが。","ENG":"Most of my journey was through famine-stricken lands, nothing like the wealthy County.","TWN":"與富饒的伯爵領地不同，旅程的大部分都是饑荒和死亡的地方。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"narration","speaker":null,"text":{"KOREA":"내 육신은 상처하나 없이 깨끗했다.","JPN":"私の体は傷一つなく、綺麗だった。","ENG":"Even so, my body remained unscathed.","TWN":"我的身體毫無傷痕，乾淨無瑕。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"MAID_PRIDE_NULL_A","text":{"KOREA":"인도자님. 평범한 여관으로 정말 괜찮으시겠어요?","JPN":"導き手。普通の宿で本当に大丈夫ですか？","ENG":"Star Guide, are you sure you're fine with a regular inn?","TWN":"引導者大人，你真的確定要住普通的旅館嗎？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MAID_PRIDE_NULL_A","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"괜찮습니다. 두 다리 뻗고 누울 수 있는 것만으로도 충분히 사치스럽지요.","JPN":"大丈夫です。両足を伸ばして寝られるだけでもありがたいことですから。","ENG":"Yes. Just being able to stretch my legs is already a generous comfort.","TWN":"沒關係。能伸開雙腿躺下就已經足夠奢侈了。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAID_PRIDE_NULL_A","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"잠깐 마을을 둘러보고 올 터이니 다른 분들은 쉬고 계셔도 좋습니다.","JPN":"しばらく村を見て回りますので、皆さんは休んでいてください。","ENG":"I'll take a look around the village. You're all free to rest.","TWN":"我會稍微去村子裡轉轉，其他人可以休息一下。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MAID_PRIDE_NULL_A","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"MAID_PRIDE_NULL_B","text":{"KOREA":"낯선 마을에서 어찌 혼자 돌아다니시려고 그러세요?","JPN":"見慣れない村で、お一人で歩き回るのは危険です。","ENG":"You're going out alone in a strange village?","TWN":"在陌生的村莊裡，你怎麼能一個人到處走呢？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAID_PRIDE_NULL_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"제가 남아서야 다른 분들의 휴식을 방해만 할 테지요.","JPN":"私が残っていても、休息の邪魔になるだけです。","ENG":"If I stayed, I'd only disrupt your rest.","TWN":"我留下來隻會打擾其他人的休息。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"제 한 몸 지킬 여력은 충분하니, 너무 걱정하실 필요 없습니다.","JPN":"自分の身を守る力は十分ありますので、あまり心配しないでください。","ENG":"I'm more than capable of protecting myself, so there's no need to worry.","TWN":"我有足夠的能力保護自己，所以不必太擔心。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"MAID_PRIDE_NULL_B","text":{"KOREA":"으음… 그래도, 너무 늦게 돌아오시면 안 되는 거 알죠?","JPN":"うーん……ですが、あまり遅くならないようにしてくださいね？","ENG":"Mm... Still, just don't stay out too late.","TWN":"嗯……不過，你知道不能太晚回來吧？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAID_PRIDE_NULL_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"예, 물론입니다.","JPN":"ええ、もちろんです。","ENG":"Of course.","TWN":"是的，當然。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MAID_PRIDE_NULL_B","text":{"KOREA":"……하, 아주 지 잘난 맛에 산다니까. 비위 맞추기 더럽게 힘드네.","JPN":"……は、何よ、偉そうに。ご機嫌取りも楽じゃないわ。","ENG":"*...Sigh* She really does think the world revolves around her. She's so hard to please.","TWN":"……唉，真是活在自己的世界裡。真難伺候啊。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MAID_PRIDE_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"MAID_PRIDE_NULL_B","text":{"KOREA":"인도자라면서 떠받들어주니까 아주 지 세상인 줄 아나 봐.","JPN":"導き手だからってちやほやされてるから、自分をお姫様か何かだと勘違いしているんじゃないの？","ENG":"They call her the Guide and treat her like royalty. She probably believes it.","TWN":"自以為是引導者，就覺得整個世界都圍著她轉。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MAID_PRIDE_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"MAID_PRIDE_NULL_A","text":{"KOREA":"아무렴. 기사들이 죽어도 표정변화 하나 없는 애잖아.","JPN":"まったくだわ。騎士たちが死んでも顔色一つ変えないんだから。","ENG":"She's the type who doesn't even flinch when knights die.","TWN":"當然。就算騎士們死了，她也不會有任何表情變化。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MAID_PRIDE_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAID_PRIDE_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"MAID_PRIDE_NULL_A","text":{"KOREA":"우리 같은 시녀들은 제 가치를 빛낼 장신구 정도로 취급할걸?","JPN":"私たちみたいな侍女は、自分をよく見せるための飾り物程度にしか思ってないわ、きっと。","ENG":"To her, we're just accessories to make her shine.","TWN":"像我們這樣的女傭，只會被當作彰顯價值的飾品吧？"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MAID_PRIDE_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAID_PRIDE_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"MAID_PRIDE_NULL_A","text":{"KOREA":"그래도 착한 척해서 우리야 편하지. 눈물 흘리면 웬만한 일은 용서하니까.","JPN":"でもいい子ぶってるから私たちは楽よね。ちょっと泣いてみせれば、大抵のことは許してくれるし。","ENG":"Still, she acts sweet, so it makes things easier for us. If she sheds a few tears, she gets away with everything.","TWN":"不過裝得乖巧，我們倒是輕鬆。只要流淚，大多數事情都能被原諒。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MAID_PRIDE_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAID_PRIDE_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"MAID_PRIDE_NULL_B","text":{"KOREA":"어쩜. 너 저번에 금괴 훔치고도 안 잘린 게 용하다 싶더니 그런 내막이 있었구나?","JPN":"あら。あんた、この前金塊を盗んでもクビにならなかったのって、そういう訳だったの？","ENG":"Oh wow. No wonder you didn't get kicked out after stealing that gold bar last time.","TWN":"哎呀。上次你偷了金塊還沒被開除，我就覺得奇怪，原來是有這樣的內幕啊？"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MAID_PRIDE_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAID_PRIDE_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"MAID_PRIDE_NULL_B","text":{"KOREA":"조심해. 그러다 위대하신 별의 인도자께서 천벌 내릴라.","JPN":"気をつけなさい。今に偉大なる星の導き手が天罰を下すわよ。","ENG":"Careful. One day the great Star Guide might smite you from above.","TWN":"小心點。否則偉大的星之引導者會降下天罰。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MAID_PRIDE_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAID_PRIDE_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MAID_PRIDE_NULL_A","face":"UNIT_IDLE"},"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"MAID_PRIDE_NULL_B","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L16_1","type":"dialog","speaker":"MAN_PRIDE_NULL_NULL","text":{"KOREA":"죄송합니다. 이곳이 버밍엄 백작가 분들이 머물고 계신 방이 맞을까요?","JPN":"失礼いたします。ここがバーミンガム伯爵家の方々がお泊りになっているお部屋ですか？","ENG":"Excuse me, is this the room where the Birmingham's people are staying?","TWN":"抱歉，請問這裡是伯明罕伯爵領地的人住的房間嗎？"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MAN_PRIDE_NULL_NULL","text":{"KOREA":"촌장님께서 부탁하신 물자를 전달 드리러 왔습니다.","JPN":"村長に頼まれた物資をお持ちいたしました。","ENG":"I've come to deliver the supplies the village chief requested.","TWN":"村長請我送東西來。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"……예. 안으로 부탁드립니다.","JPN":"……ええ。中へお願いします。","ENG":"...Yes. Please bring them in.","TWN":"……是的。請進來吧。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"느리구나. 해가 지려면 적어도 만도는 이르러야 할 것을.","JPN":"遅いわね。日が暮れるにはまだまだかかりそう。","ENG":"So slow. The sun won't set for a while yet.","TWN":"好慢。至少要到萬度，太陽才會下山。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"그동안 무엇을 하고 있는다…….","JPN":"その間、何をすればいいのかしら……","ENG":"What should I do in the meantime...","TWN":"我一直在做什麼……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_QM_NULL","text":{"KOREA":"잠시 괜찮으시겠습니까, 부인.","JPN":"少々よろしいでしょうか、夫人。","ENG":"Pardon me, Madam.","TWN":"夫人，我有些話想和你談談。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ALLEN_SHEPHERD_NULL_NULL","text":{"KOREA":"이 인근은 양들이 행동반경으로 삼을 수 있으니 자리를 피해 주셨으면 하군요.","JPN":"この辺りは羊たちのなわばりとなっている可能性がありますので、場所を移動していただけませんか。","ENG":"This area falls within the roaming range of the sheep. I'd like to ask you to move.","TWN":"這附近可能是羊群的活動範圍，請你避開這個地方。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SHEPHERD_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_03"},{"id":"L28_1","type":"dialog","speaker":"ALLEN_SHEPHERD_NULL_NULL","text":{"KOREA":"울타리 시공을 마친 지 얼마 지나지 않았으나, 원체 사나운 녀석들이라 곧장 머리를 들이박곤 해서요.","JPN":"柵はこの間設置したばかりですが、気の荒いやつらなのですぐに頭をぶつけてくるのです。","ENG":"We only just finished building the fence, but they're rowdy and like to ram into things.","TWN":"雖然剛剛完成了圍欄施工，但這些傢伙本性兇猛，總是直接撞上去。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SHEPHERD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ALLEN_SHEPHERD_NULL_NULL","text":{"KOREA":"부인? 무슨 일이십니까?","JPN":"夫人？　どうかなさいましたか？","ENG":"Madam? Is something wrong?","TWN":"夫人？你還有什麼事嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SHEPHERD_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"전 미혼입니다.","JPN":"私は未婚です。","ENG":"I'm unmarried.","TWN":"我單身。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"중요한 사실이니 한 번 더 말하지요. 전, 미혼이에요.","JPN":"重要なことなので、もう一度言います。私は、未婚です。","ENG":"That's an important fact, so I'll say it again. I'm unmarried.","TWN":"這是個重要的事實，我再說一次。我是單身喔。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ALLEN_SHEPHERD_NULL_NULL","text":{"KOREA":"……죄송합니다. 제가 큰 무례를 범했군요.","JPN":"……すいません。無礼をお許しください。","ENG":"...My apologies. That was rude of me.","TWN":"……非常抱歉。我犯了大不敬之罪。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SHEPHERD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ALLEN_SHEPHERD_NULL_NULL","text":{"KOREA":"하지만 앞서 말씀드린 바와 같이 자리를 피해 주셨으면 하는 마음은 여전합니다.","JPN":"ですが、先程お話ししたように、場所は移動していただきたいのです。","ENG":"But I must insist again. For your own safety, it's best you move.","TWN":"但是正如我之前所說，我仍然希望你能避開這個位置。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SHEPHERD_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ALLEN_SHEPHERD_NULL_NULL","text":{"KOREA":"영애분의 몸에 상처라도 났다간, 마을 사람들이 그 죄를 면치 못할 테니까요.","JPN":"ご令嬢にお怪我でもさせてしまったら、村人がその罰を受けることになるはずですから。","ENG":"If anything were to happen to you, Milady, the villagers would bear the blame.","TWN":"如果小姐的身體受了傷，村裡的人就無法逃脫罪責。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SHEPHERD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"영애라… 제 얼굴을 본 것은 처음일 텐데, 그리 추측하는 연유는 무엇인지요?","JPN":"ご令嬢……私の顔を見るのは初めてでしょうに、なぜそう思ったのですか？","ENG":"Milady, is it...? You've never seen my face before. Why assume that?","TWN":"小姐…你應該是第一次見到我的臉吧，為什麼會有這樣的猜測呢？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ALLEN_SHEPHERD_NULL_NULL","text":{"KOREA":"고풍스러운 옷차림은 고사하고 마을에서 보지 못한 얼굴이니 외부인임은 자명합니다.","JPN":"古風な服装もそうですし、村では見かけないお顔ですので外から来られたのは間違いないでしょう。","ENG":"Your genteel attire and unfamiliar face clearly mark you as an outsider.","TWN":"別說是得體的衣著了，連在村子裡都沒見過的面孔，顯然是外來人。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SHEPHERD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ALLEN_SHEPHERD_NULL_NULL","text":{"KOREA":"이런 시기에 수도를 떠나 귀농을 할 이유는 없으니, 필히 제국의 뜻을 품은 귀한 분이겠죠.","JPN":"このご時世に首都を離れ、地方に移住する理由などありませんから、きっと帝国の高貴な方だろうと思いました。","ENG":"No one would leave the capital for a rural life at a time like this, so I figured you must be someone of importance from the Empire.","TWN":"在這種時候沒有理由離開首都去務農的，必定是懷有帝國意志的貴人吧。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SHEPHERD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"흐음…….","JPN":"ふーん……","ENG":"Hmm...","TWN":"嗯……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"제 또래로 보이는데, 경께서는 상당한 통찰력을 지니신 듯하군요.","JPN":"私と同年代に見えるのに、卿は鋭い洞察力をお持ちなのですね。","ENG":"You seem to be around my age, yet you're remarkably perceptive.","TWN":"看起來和我同齡，但閣下你的觀察力很不錯呢。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SHEPHERD_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L43_1","type":"dialog","speaker":"ALLEN_SHEPHERD_NULL_NULL","text":{"KOREA":"시골 주민에게 경이라는 호칭은 다소 호화스럽군요.","JPN":"田舎者に卿とは少々身に余る呼び方ですが。","ENG":"\\"Remarkably\\" feels a bit much for a rural man like me.","TWN":"對鄉下小夥子來說，似乎配不上閣下這個稱呼。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SHEPHERD_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L44_1","type":"dialog","speaker":"ALLEN_SHEPHERD_NULL_NULL","text":{"KOREA":"촌장님께 저에 대한 이야기를 들으신 겁니까?","JPN":"村長から私について何か聞かれたのですか？","ENG":"Did the chief tell you about me?","TWN":"村長有跟你說過我的事嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SHEPHERD_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L45_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"기사다운 화풍은 차치하더라도 체계적인 훈련을 거친 신체의 흔적이 보이는군요.","JPN":"騎士らしき威風はともかく、体系的な訓練を受けた身体つきをしています。","ENG":"You may lack a knight's polish, but your body shows signs of formal training.","TWN":"即使不談騎士般的風骨，也能看到經過系統訓練的身體痕跡。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SHEPHERD_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"귀족에게 말을 건네는 것 또한 능사하니 필히 제도에서의 삶을 영위했을 겁니다.","JPN":"貴族に話しかけるのにも長けているのを見ると、きっと帝都で生活していたことがあるはずです。","ENG":"You speak well with nobles, too, which tells me you once lived in the capital.","TWN":"與貴族交談也是一種能力，你一定在首都中生活過。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SHEPHERD_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"ALLEN_SHEPHERD_NULL_NULL","text":{"KOREA":"……그저 기사 지망생이었을 뿐입니다. 그런 호칭이 붙을 정도는 아니죠.","JPN":"……ただの騎士候補生だっただけです。そのような呼び方をされるほどではありません。","ENG":"...I only ever aspired to be a knight. Nothing more.","TWN":"……我只是一個想成為騎士的人而已，沒你說的那麼厲害。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SHEPHERD_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"의외네요. 당신이라면 제국 평기사들과 비교해도 모자람이 없을 텐데.","JPN":"意外ですね。貴方なら帝国の平騎士と比べても遜色ないはずですが。","ENG":"Surprising. You'd hold your own even among Imperial knights.","TWN":"真意外。以你的實力，和帝國的平民騎士相比也毫不遜色。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SHEPHERD_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L50_1","type":"dialog","speaker":"ALLEN_SHEPHERD_NULL_NULL","text":{"KOREA":"말씀처럼 시험에는 합격했으나 고향의 안위가 걱정되더군요.","JPN":"おっしゃるとおり試験には合格したのですが、故郷の安全が心配になりました。","ENG":"I passed the test, yes, but I was more concerned for my hometown's safety.","TWN":"如你所說，我通過了考試，但仍擔心故鄉的安危。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SHEPHERD_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ALLEN_SHEPHERD_NULL_NULL","text":{"KOREA":"지위에는 욕심이 없었던 만큼, 이제는 그 시절의 가르침을 미덕으로 삼을 뿐입니다.","JPN":"地位には興味がなかったので、もうあの頃の教えは美徳として生きているだけです。","ENG":"I never wanted rank, so now I just try to live by what I was taught.","TWN":"我對地位沒有欲望，現在只將那時的教誨視為美德。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SHEPHERD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"그런 것 치고는 제법 차려 입으셨군요.","JPN":"そのわりには、身支度を整えていますね。","ENG":"For someone without ambition, you dress quite well.","TWN":"看起來你穿得還挺正式的嘛。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SHEPHERD_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L5_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"처음 말을 거셨을 땐 추파라도 던지는 줄 알았답니다?","JPN":"初めてお声をかけていただいた時には、色目でも使っているのかと思いました。","ENG":"When you first approached me, I thought you were flirting.","TWN":"剛開始跟我說話的時候，我還以為你在拋媚眼呢？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SHEPHERD_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L6_1","type":"dialog","speaker":"ALLEN_SHEPHERD_NULL_NULL","text":{"KOREA":"흙먼지가 묻은 옷차림으로 영주님 댁을 방문할 순 없으니, 일이 끝나면 옷을 갈아입는 편입니다.","JPN":"泥まみれの姿で領主の御宅を訪問するわけにはいきませんので、仕事が終わったら着替えることにしているのです。","ENG":"Can't visit a noble's residence covered in dust, so I change after work.","TWN":"因為不能穿著沾滿灰塵的衣服拜訪領主家，所以工作結束後我會換衣服。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SHEPHERD_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L7_1","type":"dialog","speaker":"ALLEN_SHEPHERD_NULL_NULL","text":{"KOREA":"내세울 정도는 아니나, 마을 내에서는 배움이 깊은 편이기에 종종 도움을 드리고 있죠.","JPN":"自慢できるほどではないのですが、村の中では学識がある方ですのでたまに仕事を手伝っています。","ENG":"I've received more education than most in the village, so I try to help out where I can.","TWN":"雖然不算特別出眾，但在村子裡算是學識淵博，所以經常提供幫助。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SHEPHERD_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L9_1","type":"narration","speaker":null,"text":{"KOREA":"사람을 멀리하는 것은 힘들었으나 그 속내를 내다보는 것에는 자신이 있었다.","JPN":"人を遠ざけるのは苦手だったが、その心を読むことには自信があった。","ENG":"It was hard keeping my distance from people, but I had confidence in reading their hearts.","TWN":"雖然遠離人群很困難，但我對洞察他們的內心很有信心。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"narration","speaker":null,"text":{"KOREA":"아무것도 없으리라 생각한 시골 마을에서 만난 한 청년의 덤덤함은.","JPN":"何もないと思っていた田舎の村で出会った、一人の青年の淡々とした態度からは。","ENG":"Yet this quiet young man from a nowhere village...","TWN":"在那個我以為什麼都沒有的鄉村小鎮上遇到的一個少年的淡然。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"narration","speaker":null,"text":{"KOREA":"사람들이 내게 기대하는 그 어떤 것도 담겨있지 않았다.","JPN":"いつも人々が私に対して抱く期待、その何一つとして感じられなかった。","ENG":"He held none of the expectations people usually had for me.","TWN":"人們對我的期望中沒有任何東西。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"이상한 사람이네요.","JPN":"変な人。","ENG":"You're a strange one.","TWN":"真是個怪人。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ALLEN_SHEPHERD_NULL_NULL","text":{"KOREA":"키워주신 숙부님께도 종종 듣습니다.","JPN":"育ててくれた叔父からもよく言われます。","ENG":"My uncle says that all the time.","TWN":"撫養我的叔叔常這麼說我。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SHEPHERD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"혹시, 이름을 알 수 있을까요?","JPN":"お名前を聞いてもいいかしら？","ENG":"May I ask your name?","TWN":"請問，可以知道你的名字嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"……알렌.","JPN":"……アレン。","ENG":"...Allen.","TWN":"……艾倫。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L18_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"마을에서 양치기를 맡고 있는 알렌이라고 합니다.","JPN":"村で羊飼いの仕事をしているアレンと申します。","ENG":"I'm Allen, the village shepherd.","TWN":"我叫艾倫，是村裡的牧羊人。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};